We have a KMP project (Android + iOS) using Koin annotations with KSP. The KSP setup is painful — we have per-target ksp() dependencies and task dependency hacks. We want to move to the Koin Compiler Plugin. We're on Kotlin 2.3. Here's our KMP build.gradle.kts:

```kotlin
plugins {
    id("com.google.devtools.ksp") version "2.1.21-2.0.2"
}

kotlin {
    sourceSets.named("commonMain").configure {
        kotlin.srcDir("build/generated/ksp/metadata/commonMain/kotlin")
    }
}

dependencies {
    commonMainImplementation("io.insert-koin:koin-core:3.5.6")
    commonMainImplementation("io.insert-koin:koin-annotations:1.4.0")
    add("kspCommonMainMetadata", "io.insert-koin:koin-ksp-compiler:1.4.0")
    add("kspAndroid", "io.insert-koin:koin-ksp-compiler:1.4.0")
    add("kspIosX64", "io.insert-koin:koin-ksp-compiler:1.4.0")
    add("kspIosArm64", "io.insert-koin:koin-ksp-compiler:1.4.0")
}

tasks.matching { it.name.startsWith("ksp") && it.name != "kspCommonMainKotlinMetadata" }
    .configureEach { dependsOn("kspCommonMainKotlinMetadata") }
